            ContentJson = """{"title":"Payments Field Reference","groups":[{"heading":"Payment Details (New Payment Panel)","items":[{"label":"Customer (required)","value":"Pick which customer made the payment from the menu of your customers."},{"label":"Payment Method (required)","value":"Choose how they paid: cash, check, credit card, bank transfer, wire, or other."},{"label":"Amount (required)","value":"How much you received. Must be more than $0.00."},{"label":"Payment Date (required)","value":"The date you received the payment."},{"label":"Reference Number (optional)","value":"A check number, wire confirmation, transaction ID, or any outside reference you want to keep."},{"label":"Notes (optional)","value":"Anything else you want to jot down about the payment."}]},{"heading":"Applying to Invoices (New Payment Panel)","items":[{"label":"Invoice (required)","value":"The invoice you want this payment to go toward."},{"label":"Invoice Number (required)","value":"The invoice's number, shown so you can confirm you picked the right one."},{"label":"Amount (required)","value":"How much of the payment goes to this invoice. Must be more than $0.00 and no more than what the invoice still owes."},{"label":"Add button","value":"Adds this invoice to the list below. Stays greyed out until every box is filled in correctly."},{"label":"Remove button","value":"Takes an invoice back off the list."},{"label":"Total Applied","value":"Adds up everything you've applied so far. Can't be more than the payment amount."}]},{"heading":"Payment Methods","items":[{"label":"Cash","value":"Physical cash received from the customer."},{"label":"Check","value":"A paper check. Put the check number in Reference Number."},{"label":"Credit Card","value":"A card payment. Reference Number can hold the last four digits or the transaction ID."},{"label":"Bank Transfer","value":"An ACH or direct bank transfer. Reference Number can hold the confirmation."},{"label":"Wire","value":"A wire transfer. Reference Number holds the wire confirmation number."},{"label":"Other","value":"Any method not listed above. Use Notes to describe it."}]},{"heading":"Columns in the Payments List","items":[{"label":"Payment #","value":"The payment's number, created for you. Click to sort."},{"label":"Customer","value":"The customer who made the payment. Click to sort."},{"label":"Method","value":"How they paid, such as cash or check. Sort or filter by it."},{"label":"Amount","value":"The full amount received. Click to sort."},{"label":"Applied","value":"How much of it has been put toward invoices. Click to sort."},{"label":"Unapplied","value":"What's left over, not yet on any invoice. Turns yellow when it's above $0.00. Click to sort."},{"label":"Date","value":"The date the payment was received. Click to sort."},{"label":"Reference #","value":"The reference number, or '---' if there isn't one. Click to sort."},{"label":"Created","value":"The date the payment was entered. Click to sort."}]},{"heading":"What You See When You Open a Payment","items":[{"label":"Payment Number","value":"The payment's number, shown at the top."},{"label":"Customer","value":"The customer who paid. Click their name to open their record."},{"label":"Method","value":"How they paid."},{"label":"Payment Date","value":"The date the payment was received."},{"label":"Reference Number","value":"The reference number. Hidden when there isn't one."},{"label":"Amount","value":"The full amount received."},{"label":"Applied","value":"How much has been put toward invoices."},{"label":"Unapplied","value":"What's left over. Turns yellow when it's above $0.00."},{"label":"Notes","value":"Any notes on the payment. Hidden when there aren't any."},{"label":"Applications list","value":"Each invoice this payment went toward, with its number and amount. The heading shows how many."},{"label":"Created / Updated","value":"When the payment was entered and last changed."},{"label":"Activity History","value":"A timeline of what's happened to this payment."}]},{"heading":"Buttons and Actions","items":[{"label":"Record Payment (top of the page)","value":"Opens the panel to record a new payment. Only shows when you're not connected to an outside accounting system."},{"label":"Create Payment (bottom of the panel)","value":"Saves the new payment and the invoices you applied it to. Greyed out until the form is complete. If something's missing, a warning icon shows how many items need attention — click it to see which."},{"label":"Cancel","value":"Closes the panel without saving."},{"label":"Close","value":"Closes the payment you were viewing."},{"label":"Delete","value":"Removes the payment after you confirm. Only shows when the payment isn't applied to any invoice."},{"label":"Click a row","value":"Opens that payment to see all its details, the invoices it went toward, its history, and the delete option."}]},{"heading":"Rules to Know","items":[{"label":"Customer","value":"Required. Pick a customer before saving."},{"label":"Payment Method","value":"Required. Choose one of the six methods."},{"label":"Amount","value":"Required. Must be more than $0.00."},{"label":"Payment Date","value":"Required. Pick a date."},{"label":"Amount applied to each invoice","value":"Must be more than $0.00 and no more than what that invoice still owes."},{"label":"Total applied","value":"Everything applied together can't be more than the payment amount."},{"label":"Deleting","value":"You can only delete a payment that isn't applied to any invoice. Remove it from every invoice first."},{"label":"Missing-info warning","value":"When something's missing, a warning icon by Create Payment shows how many items need attention. Click it to see which."}]},{"heading":"Connected to an Accounting System?","items":[{"label":"Not connected","value":"You can do it all: record payments, view details, and delete (when not applied). The Record Payment button is there and every field can be edited."},{"label":"Connected","value":"View only. A blue banner says payments are handled by your accounting system. The Record Payment button is hidden and payments flow in from that system. You can still open a payment to view it, but not create or delete."},{"label":"Where the banner appears","value":"Just below the page title, whenever an accounting system is connected."}]}]}"""
